package main

import (
	"html/template"
	"net/http"
)

type Comment struct {
	Author string
	Body   string
}

func main() {
	comments := []Comment{
		{Author: "Alice", Body: "Hello <b>world</b>!"},
		{Author: "Bob", Body: "This is a <script>alert('xss')</script> test"},
		{Author: "Charlie", Body: "Normal comment without HTML"},
	}

	http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		tmpl := template.Must(template.New("comments").Parse(`
<!DOCTYPE html>
<html>
<head>
    <title>Comments</title>
</head>
<body>
    <h1>User Comments</h1>
    {{range .}}
    <div>
        <strong>{{.Author}}</strong>
        <p>{{.Body}}</p>
    </div>
    <hr>
    {{end}}
</body>
</html>
`))
		err := tmpl.Execute(w, comments)
		if err != nil {
			http.Error(w, err.Error(), http.StatusInternalServerError)
			return
		}
	})

	http.ListenAndServe(":8080", nil)
}